import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Save, IndianRupee } from 'lucide-react';

const BillingForm = ({ onSave }) => {
  const [formData, setFormData] = useState({
    customerName: '',
    customerPhone: '',
    customerAddress: '',
    items: [{ name: '', quantity: 1, rate: 0, amount: 0 }],
    discount: 0,
    subtotal: 0,
    finalTotal: 0
  });

  useEffect(() => {
    const subtotal = formData.items.reduce((sum, item) => sum + (parseFloat(item.amount) || 0), 0);
    const finalTotal = subtotal - (parseFloat(formData.discount) || 0);
    setFormData(prev => ({ ...prev, subtotal, finalTotal }));
  }, [formData.items, formData.discount]);

  const handleItemChange = (index, field, value) => {
    const newItems = [...formData.items];
    newItems[index][field] = value;

    if (field === 'quantity' || field === 'rate') {
      const q = parseFloat(newItems[index].quantity) || 0;
      const r = parseFloat(newItems[index].rate) || 0;
      newItems[index].amount = q * r;
    }

    setFormData({ ...formData, items: newItems });
  };

  const addItem = () => {
    setFormData({
      ...formData,
      items: [...formData.items, { name: '', quantity: 1, rate: 0, amount: 0 }]
    });
  };

  const removeItem = (index) => {
    const newItems = formData.items.filter((_, i) => i !== index);
    setFormData({ ...formData, items: newItems });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const invoice = {
      ...formData,
      id: 'INV-' + Date.now().toString().slice(-6),
      date: new Date().toLocaleDateString('en-IN'),
      timestamp: Date.now()
    };
    onSave(invoice);
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="glass p-8 rounded-2xl shadow-xl border border-white/10">
        <h2 className="text-3xl font-bold mb-8 flex items-center gap-3">
          <IndianRupee className="text-yellow-500" /> Create New Invoice
        </h2>

        <form onSubmit={handleSubmit} className="space-y-8">
          {/* Customer Details */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-400">Customer Name</label>
              <input
                required
                type="text"
                value={formData.customerName}
                onChange={(e) => setFormData({...formData, customerName: e.target.value})}
                className="w-full bg-black/30 border border-gray-700 rounded-lg p-3 focus:border-yellow-500 outline-none transition"
                placeholder="Enter customer name"
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-400">Phone Number</label>
              <input
                required
                type="tel"
                value={formData.customerPhone}
                onChange={(e) => setFormData({...formData, customerPhone: e.target.value})}
                className="w-full bg-black/30 border border-gray-700 rounded-lg p-3 focus:border-yellow-500 outline-none transition"
                placeholder="10 digit mobile number"
              />
            </div>
            <div className="md:col-span-2 space-y-2">
              <label className="text-sm font-medium text-gray-400">Address</label>
              <textarea
                value={formData.customerAddress}
                onChange={(e) => setFormData({...formData, customerAddress: e.target.value})}
                className="w-full bg-black/30 border border-gray-700 rounded-lg p-3 focus:border-yellow-500 outline-none transition h-20"
                placeholder="Customer full address"
              ></textarea>
            </div>
          </div>

          {/* Items Table */}
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold">Services / Items</h3>
              <button
                type="button"
                onClick={addItem}
                className="text-sm bg-yellow-500/10 text-yellow-500 border border-yellow-500/20 px-4 py-2 rounded-lg hover:bg-yellow-500 hover:text-black transition flex items-center gap-2"
              >
                <Plus size={16} /> Add Item
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="border-b border-gray-800 text-gray-400 text-sm">
                    <th className="pb-4 font-medium">Item Name</th>
                    <th className="pb-4 font-medium w-24">Qty</th>
                    <th className="pb-4 font-medium w-32">Rate (₹)</th>
                    <th className="pb-4 font-medium w-32">Amount (₹)</th>
                    <th className="pb-4 w-10"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-800">
                  {formData.items.map((item, index) => (
                    <tr key={index} className="group">
                      <td className="py-4 pr-4">
                        <input
                          required
                          type="text"
                          value={item.name}
                          onChange={(e) => handleItemChange(index, 'name', e.target.value)}
                          className="w-full bg-transparent border-b border-transparent focus:border-yellow-500 outline-none"
                          placeholder="e.g. Fan Repair"
                        />
                      </td>
                      <td className="py-4 pr-4">
                        <input
                          type="number"
                          value={item.quantity}
                          onChange={(e) => handleItemChange(index, 'quantity', e.target.value)}
                          className="w-full bg-transparent border-b border-transparent focus:border-yellow-500 outline-none"
                        />
                      </td>
                      <td className="py-4 pr-4">
                        <input
                          type="number"
                          value={item.rate}
                          onChange={(e) => handleItemChange(index, 'rate', e.target.value)}
                          className="w-full bg-transparent border-b border-transparent focus:border-yellow-500 outline-none"
                        />
                      </td>
                      <td className="py-4 font-bold">
                        ₹{item.amount}
                      </td>
                      <td className="py-4">
                        {formData.items.length > 1 && (
                          <button
                            type="button"
                            onClick={() => removeItem(index)}
                            className="text-gray-600 hover:text-red-500 transition"
                          >
                            <Trash2 size={18} />
                          </button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Totals */}
          <div className="flex flex-col items-end gap-4 border-t border-gray-800 pt-8">
            <div className="flex items-center gap-12 text-gray-400">
              <span>Subtotal:</span>
              <span className="text-white font-bold text-xl">₹{formData.subtotal}</span>
            </div>
            <div className="flex items-center gap-12">
              <span className="text-gray-400">Discount:</span>
              <input
                type="number"
                value={formData.discount}
                onChange={(e) => setFormData({...formData, discount: e.target.value})}
                className="w-32 bg-black/30 border border-gray-700 rounded-lg p-2 text-right focus:border-yellow-500 outline-none"
              />
            </div>
            <div className="flex items-center gap-12 text-2xl font-black">
              <span className="gold-text-gradient uppercase tracking-widest">Total Amount:</span>
              <span className="text-yellow-500">₹{formData.finalTotal}</span>
            </div>
          </div>

          <button
            type="submit"
            className="w-full py-4 gold-gradient rounded-xl text-black font-black text-lg hover:shadow-[0_0_30px_rgba(234,179,8,0.3)] transition-all flex items-center justify-center gap-2"
          >
            <Save size={20} /> GENERATE & SAVE BILL
          </button>
        </form>
      </div>
    </div>
  );
};

export default BillingForm;
